var theBook = createBibleBook(false, {
  "id":            "John",
  "title":         { "en":"John", "fr":"Jean" },
  "chapter_count": 21,
  "langs":         [ "en", "fr" ],

  "descriptions": [
    "[Wikipedia] The <b>Gospel of John</b>, the fourth of the gospels, is a highly schematic account of the ministry of Jesus, with seven \"signs\" culminating in the raising of Lazarus (foreshadowing the resurrection of Jesus) and seven \"I am\" discourses culminating in Thomas's proclamation of the risen Jesus as \"my Lord and my God\"; the concluding verses set out its purpose, \"that you may believe that Jesus is the Christ, the Son of God, and that believing you may have life in his name.\"#John reached its final form around AD 90–110, although it contains signs of origins dating back to AD 70 and possibly even earlier. Like the three other gospels, it is anonymous, although it identifies an unnamed \"disciple whom Jesus loved\" as the source of its traditions. It most likely arose within a \"Johannine community\", and as it is closely related in style and content to the three Johannine epistles most scholars treat the four books, along with the Book of Revelation, as a single corpus of Johannine literature, albeit not from the same author.#The discourses seem to be concerned with issues of the church–synagogue debate at the time of composition.",
  ],

});

